def configure_api_gateway(config: Dict, admin_url: str = "http://localhost:8001"):
    client = KongAdminClient(admin_url)
    
    print("Checking Kong Admin API health...")
    try:
        health = client.health_check()
        print(f"Kong is healthy: {json.dumps(health, indent=2)}")
    except Exception as e:
        print(f"Failed to connect to Kong Admin API: {e}")
        return
    
    for upstream_config in config.get('upstreams', []):
        upstream_name = upstream_config['name']
        print(f"\nConfiguring upstream: {upstream_name}")
        
        existing = client.get_upstream(upstream_name)
        if existing:
            print(f"Upstream {upstream_name} already exists, updating...")
            upstream = client.update_upstream(upstream_name, **{k: v for k, v in upstream_config.items() if k not in ['name', 'targets']})
        else:
            upstream = client.create_upstream(upstream_name, **{k: v for k, v in upstream_config.items() if k not in ['name', 'targets']})
        
        print(f"Upstream created/updated: {upstream['id']}")
        
        existing_targets = client.list_targets(upstream_name)
        for target_config in upstream_config.get('targets', []):
            target_host = target_config['target']
            weight = target_config.get('weight', 100)
            
            target_exists = any(t['target'] == target_host for t in existing_targets)
            if not target_exists:
                print(f"Adding target: {target_host} with weight {weight}")
                client.create_target(upstream_name, target_host, weight)
            else:
                print(f"Target {target_host} already exists")
    
    for service_config in config.get('services', []):
        service_name = service_config['name']
        print(f"\nConfiguring service: {service_name}")
        
        existing = client.get_service(service_name)
        if existing:
            print(f"Service {service_name} already exists, updating...")
            service = client.update_service(service_name, **{k: v for k, v in service_config.items() if k not in ['name', 'routes', 'plugins']})
        else:
            service = client.create_service(service_name, **{k: v for k, v in service_config.items() if k not in ['routes', 'plugins']})
        
        print(f"Service created/updated: {service['id']}")
        
        for route_config in service_config.get('routes', []):
            route_name = route_config.get('name')
            print(f"Configuring route: {route_name or 'unnamed'}")
            
            if route_name:
                existing_route = client.get_route(route_name)
                if existing_route:
                    print(f"Route {route_name} already exists, updating...")
                    route = client.update_route(route_name, **{k: v for k, v in route_config.items() if k != 'name'})
                else:
                    route = client.create_route(service_name, **route_config)
            else:
                route = client.create_route(service_name, **route_config)
            
            print(f"Route created/updated: {route['id']}")
        
        for plugin_config in service_config.get('plugins', []):
            plugin_name = plugin_config['name']
            print(f"Adding plugin {plugin_name} to service {service_name}")
            plugin = client.add_plugin(
                name=plugin_name,
                service_id=service['id'],
                config=plugin_config.get('config'),
                **{k: v for k, v in plugin_config.items() if k not in ['name', 'config']}
            )
            print(f"Plugin added: {plugin['id']}")
    
    for consumer_config in config.get('consumers', []):
        consumer_username = consumer_config['username']
        print(f"\nConfiguring consumer: {consumer_username}")
        
        existing = client.get_consumer(consumer_username)
        if not existing:
            consumer = client.create_consumer(**consumer_config)
            print(f"Consumer created: {consumer['id']}")
        else:
            print(f"Consumer {consumer_username} already exists")
    
    for plugin_config in config.get('global_plugins', []):
        plugin_name = plugin_config['name']
        print(f"\nAdding global plugin: {plugin_name}")
        plugin = client.add_plugin(
            name=plugin_name,
            config=plugin_config.get('config'),
            **{k: v for k, v in plugin_config.items() if k not in ['name', 'config']}
        )
        print(f"Global plugin added: {plugin['id']}")
    
    print("\nKong configuration completed successfully!")


